      out.write("<!-- 强制保留一位小数点-->\n");
      out.write("\n");
      out.write("<script>\n");
      out.write("function changeTwoDecimal_f(x)\n");
      out.write("{\n");
      out.write("　　var f_x = parseFloat(x);\n");
      out.write("　　if (isNaN(f_x))\n");
      out.write("　　{\n");
      out.write("　　　　return 0;\n");
      out.write("　　}\n");
      out.write("　　var f_x = Math.round(x*100)/100;\n");
      out.write("　　var s_x = f_x.toString();\n");
      out.write("　　var pos_decimal = s_x.indexOf('.');\n");
      out.write("　　if (pos_decimal < 0)\n");
      out.write("　　{\n");
      out.write("　　　　pos_decimal = s_x.length;\n");
      out.write("　　s_x += '.';\n");
      out.write("　　}\n");
      out.write("　　while (s_x.length <= pos_decimal + 1)\n");
      out.write("　　{\n");
      out.write("　　　　s_x += '0';\n");
      out.write("　　}\n");
      out.write("　　return s_x;\n");
      out.write("}\n");
      out.write("</script>\n");
      out.write("\n");
      out.write("<!-- string cst时间转date-->\n");
      out.write("\n");
      out.write("<script>\n");
      out.write("     function dateFormat(date, format) {\n");
      out.write("        date = new Date(date);\n");
      out.write("        var o = {\n");
      out.write("            'M+' : date.getMonth() + 1, //month\n");
      out.write("            'd+' : date.getDate(), //day\n");
      out.write("    };\n");
      out.write("    if (/(y+)/.test(format))\n");
      out.write("        format = format.replace(RegExp.$1, (date.getFullYear() + '').substr(4 - RegExp.$1.length));\n");
      out.write("\n");
      out.write("    for (var k in o)\n");
      out.write("        if (new RegExp('(' + k + ')').test(format))\n");
      out.write("            format = format.replace(RegExp.$1, RegExp.$1.length == 1 ? o[k] : ('00' + o[k]).substr(('' + o[k]).length));\n");
      out.write("    return format;\n");
      out.write("    }\n");
      out.write("</script>\n");
      out.write("\n");
      out.write("\n");
